const formSlug = K('form').slug();
const kappSlug = K('kapp').slug();
// Confirm bundle.ext exists, or create it
bundle.ext = bundle.ext || {};
// Confirm bundle.ext.forms.<form_slug> exists, or create it
bundle.ext.forms = bundle.ext.forms || {};
bundle.ext.forms[formSlug] = bundle.ext.forms[formSlug] || {};
