class HierarchicalDropdown {
  constructor(containerElement, options = {}) {
    this.container = containerElement;
    this.options = options;
    this.activeFlyout = null;
    this.currentTarget = null; // Currently focused eligible field
    this.eligibleFieldClass = options.eligibleFieldClass || 'dropdown-enabled';
    this.isVisible = false; // Track dropdown visibility

    // Data structure for menu items
    this.menuData = {
      'Snippets': [],
      'Space': [],
      'Kapp': [],
      'Form': [],
      'Submission': [],
      'Variables': [],
      'Date Formats': []
    };

    this.init();
  }

  init() {
    this.createStructure();
    this.bindFieldEvents();
    this.bindMenuEvents();
    this.bindButtonEvents();
  }

  createStructure() {
    this.container.innerHTML = `
      <div class="hierarchical-dropdown-wrapper">
        <button type="button" class="kbtn kbtn-lg dynamic-refs-toggle bg-primary">
          Insert Dynamic References
        </button>
        <div class="hierarchical-dropdown" style="display: none; position: absolute; z-index: 1000; background: white; border: 1px solid #ddd; border-radius: 6px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); min-width: 250px; max-width: 400px;">
          <div class="dropdown-status">
            <span class="status-text">Select a template field to insert variables</span>
          </div>
          <div class="dropdown-main-menu">
            ${this.createMainMenuItems()}
          </div>
          <div class="dropdown-flyout" style="display: none;"></div>
        </div>
      </div>
    `;

    this.toggleBtn = this.container.querySelector('.dynamic-refs-toggle');
    this.dropdownWrapper = this.container.querySelector('.hierarchical-dropdown');
    this.statusElement = this.container.querySelector('.status-text');
    this.mainMenu = this.container.querySelector('.dropdown-main-menu');
    this.flyoutMenu = this.container.querySelector('.dropdown-flyout');

    // Add custom styling
    this.addCustomStyles();
  }

  addCustomStyles() {
    if (!document.getElementById('hierarchical-dropdown-styles')) {
      const styleSheet = document.createElement('style');
      styleSheet.id = 'hierarchical-dropdown-styles';
      styleSheet.textContent = `
        .hierarchical-dropdown-wrapper {
          position: relative;
          width: 100%;
          margin-bottom: 1.25rem;
        }

        .hierarchical-dropdown {
          margin-top: 0.5rem;
        }

        .dropdown-status {
          padding: 8px 12px;
          background: #f8f9fa;
          border-bottom: 1px solid #e9ecef;
          border-radius: 6px 6px 0 0;
          font-size: 12px;
          color: #6c757d;
          text-align: center;
        }

        .hierarchical-dropdown-wrapper.field-targeted .dropdown-status {
          background: #d4edda;
          color: #155724;
          border-bottom-color: #c3e6cb;
        }

        .dropdown-main-menu {
          background: white;
          min-width: 150px;
          max-height: 300px;
          overflow-y: auto;
        }

        .dropdown-flyout {
          position: absolute;
          background: white;
          border: 1px solid #ccc;
          border-radius: 4px;
          box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
          min-width: 400px;
          max-height: 400px;
          overflow-y: auto;
          z-index: 1001;
        }

        .dropdown-item {
          padding: 8px 12px;
          cursor: pointer;
          border-bottom: 1px solid #f0f0f0;
          display: flex;
          justify-content: space-between;
          align-items: center;
          line-height: 1.4;
          color: #333;
          background-color: white;
          min-height: 32px;
        }

        .dropdown-item:last-child {
          border-bottom: none;
        }

        .dropdown-item:hover:not(.disabled):not(.section-title) {
          background-color: #f5f5f5;
        }

        .dropdown-item.main-item {
          background-color: #fafafa;
          font-weight: 500;
        }

        .dropdown-item.main-item:hover {
          background-color: #e8e8e8;
        }

        .dropdown-item.main-item .arrow {
          color: #666;
          font-size: 12px;
        }

        .dropdown-item.selectable-item {
          background-color: white;
          font-weight: normal;
        }

        .dropdown-item.selectable-item:hover {
          background-color: #e8f4fd;
          color: #0066cc;
        }

        .dropdown-item.disabled {
          color: #999;
          cursor: not-allowed;
          font-style: italic;
        }

        .dropdown-item.section-title {
          background-color: #f8f9fa;
          color: #495057;
          font-weight: 600;
          font-size: 12px;
          text-transform: uppercase;
          letter-spacing: 0.5px;
          cursor: default;
          padding: 6px 12px;
        }

        .dropdown-separator {
          height: 1px;
          background-color: #e0e0e0;
          margin: 4px 0;
        }

        .dropdown-item.date-format-item {
          font-family: 'Courier New', monospace;
          font-size: 13px;
        }

        .dropdown-main-menu::-webkit-scrollbar,
        .dropdown-flyout::-webkit-scrollbar {
          width: 6px;
        }

        .dropdown-main-menu::-webkit-scrollbar-track,
        .dropdown-flyout::-webkit-scrollbar-track {
          background: #f1f1f1;
          border-radius: 3px;
        }

        .dropdown-main-menu::-webkit-scrollbar-thumb,
        .dropdown-flyout::-webkit-scrollbar-thumb {
          background: #c1c1c1;
          border-radius: 3px;
        }

        .dropdown-main-menu::-webkit-scrollbar-thumb:hover,
        .dropdown-flyout::-webkit-scrollbar-thumb:hover {
          background: #a8a8a8;
        }
      `;
      document.head.appendChild(styleSheet);
    }
  }

  bindButtonEvents() {
    this.toggleBtn.addEventListener('click', (e) => {
      e.preventDefault();
      this.toggleDropdown();
    });

    // Close when clicking outside
    document.addEventListener('click', (e) => {
      if (this.isVisible && !this.container.contains(e.target)) {
        this.hide();
      }
    });
  }

  toggleDropdown() {
    if (this.isVisible) {
      this.hide();
    } else {
      this.show();
    }
  }

  show() {
    this.isVisible = true;
    this.dropdownWrapper.style.display = 'block';
  }

  hide() {
    this.isVisible = false;
    this.dropdownWrapper.style.display = 'none';
    this.hideFlyout();
  }

  createMainMenuItems() {
    const mainItems = ['Snippets', 'Space', 'Kapp', 'Form', 'Submission', 'Variables', 'Date Formats'];
    return mainItems.map(item =>
        `<div class="dropdown-item main-item" data-category="${item}">
        <span>${item}</span>
        <span class="arrow">▶</span>
      </div>`
    ).join('');
  }

  bindFieldEvents() {
    // Listen for focus/blur on all form fields
    document.addEventListener('focusin', (e) => {
      this.handleFieldFocus(e.target);
    });

    document.addEventListener('focusout', (e) => {
      // Small delay to handle rapid focus changes
      setTimeout(() => {
        if (!document.activeElement || !this.isEligibleField(document.activeElement)) {
          this.handleFieldBlur();
        }
      }, 50);
    });
  }

  bindMenuEvents() {
    // Use event delegation for better event handling
    this.mainMenu.addEventListener('mouseover', (e) => {
      // Find the closest main-item (in case we're hovering over a child element)
      const mainItem = e.target.closest('.main-item');
      if (mainItem) {
        this.showFlyout(mainItem.dataset.category, mainItem);
      }
    });

    this.mainMenu.addEventListener('mouseleave', (e) => {
      setTimeout(() => {
        if (!this.flyoutMenu.matches(':hover') && !this.mainMenu.matches(':hover')) {
          this.hideFlyout();
        }
      }, 100);
    });

    // Flyout menu events
    this.flyoutMenu.addEventListener('mouseleave', () => {
      setTimeout(() => {
        if (!this.flyoutMenu.matches(':hover') && !this.mainMenu.matches(':hover')) {
          this.hideFlyout();
        }
      }, 100);
    });

    this.flyoutMenu.addEventListener('click', (e) => {
      if (e.target.classList.contains('selectable-item')) {
        this.handleSelection(e.target);
      }
    });

    // Prevent menu clicks from changing focus
    this.container.addEventListener('mousedown', (e) => {
      e.preventDefault();
    });
  }

  isEligibleField(element) {
    return element &&
        (element.tagName.toLowerCase() === 'input' || element.tagName.toLowerCase() === 'textarea') &&
        element.classList.contains(this.eligibleFieldClass);
  }

  handleFieldFocus(element) {
    if (this.isEligibleField(element)) {
      this.currentTarget = element;
      this.updateStatus(`Ready to insert into: ${this.getFieldDisplayName(element)}`);
      this.container.classList.add('field-targeted');
    }
  }

  handleFieldBlur() {
    this.currentTarget = null;
    this.updateStatus('Select a template field to insert variables');
    this.container.classList.remove('field-targeted');
  }

  getFieldDisplayName(element) {
    // Try to get a friendly name for the field
    const label = element.getAttribute('aria-label') ||
        element.getAttribute('placeholder') ||
        element.getAttribute('name') ||
        element.getAttribute('id') ||
        'field';
    return label;
  }

  updateStatus(message) {
    this.statusElement.textContent = message;
  }

  showFlyout(category, triggerElement) {
    // Don't show flyout if no field is targeted
    if (!this.currentTarget) {
      this.updateStatus('Please focus on a template field first');
      return;
    }

    this.activeFlyout = category;
    const flyoutContent = this.generateFlyoutContent(category);
    this.flyoutMenu.innerHTML = flyoutContent;

    // Position flyout next to trigger element
    const rect = triggerElement.getBoundingClientRect();
    const dropdownRect = this.dropdownWrapper.getBoundingClientRect();

    this.flyoutMenu.style.display = 'block';
    this.flyoutMenu.style.left = `${rect.width}px`;
    this.flyoutMenu.style.top = `${rect.top - dropdownRect.top}px`;
  }

  hideFlyout() {
    this.flyoutMenu.style.display = 'none';
    this.activeFlyout = null;
  }

  generateFlyoutContent(category) {
    const data = this.menuData[category] || [];

    switch (category) {
      case 'Snippets':
        return this.generateSimpleList(data);

      case 'Space':
        return this.generateStandardPlusCustomList(data, 'Space Attributes');

      case 'Kapp':
        return this.generateStandardPlusCustomList(data, 'Kapp Attributes');

      case 'Form':
        return this.generateStandardPlusCustomList(data, 'Form Attributes');

      case 'Submission':
        return this.generateStandardPlusCustomList(data, 'Submission Fields');

      case 'Variables':
        return this.generateVariablesList(data);

      case 'Date Formats':
        return this.generateDateFormatsList(data);

      default:
        return '<div class="dropdown-item">No items available</div>';
    }
  }

  generateSimpleList(items) {
    if (!items.length) {
      return '<div class="dropdown-item disabled">No items available</div>';
    }

    return items.map(item =>
        `<div class="dropdown-item selectable-item" data-value="${item.value}">
        ${item.label}
      </div>`
    ).join('');
  }

  generateStandardPlusCustomList(items, customTitle) {
    if (!items.length) {
      return '<div class="dropdown-item disabled">No items available</div>';
    }

    const standardItems = items.filter(item => item.isStandard);
    const customItems = items.filter(item => !item.isStandard);

    let html = '';

    // Standard items first
    if (standardItems.length) {
      html += standardItems.map(item =>
          `<div class="dropdown-item selectable-item" data-value="${item.value}">
          ${item.label}
        </div>`
      ).join('');
    }

    // Separator and custom items
    if (customItems.length) {
      if (standardItems.length) {
        html += '<div class="dropdown-separator"></div>';
      }
      html += `<div class="dropdown-item section-title">${customTitle}</div>`;
      html += customItems.map(item =>
          `<div class="dropdown-item selectable-item" data-value="${item.value}">
          ${item.label}
        </div>`
      ).join('');
    }

    return html || '<div class="dropdown-item disabled">No items available</div>';
  }

  generateVariablesList(items) {
    //let html = '<div class="dropdown-item section-title">Available Variables</div>';
    let html = '<div class="dropdown-item section-title">Provided at run-time to the Task Engine. Select the placeholder below and manually enter the variable name.</div>';

    if (!items.length) {
      html += '<div class="dropdown-item disabled">No variables defined</div>';
    } else {
      html += items.map(item =>
          `<div class="dropdown-item selectable-item" data-value="${item.value}">
          ${item.label}
        </div>`
      ).join('');
    }

    return html;
  }

  generateDateFormatsList(items) {
    const selectedElement = this.getSelectedDateElement();

    if (!selectedElement) {
      return '<div class="dropdown-item disabled">Please select a date element first</div>';
    }

    let html = `<div class="dropdown-item section-title">Formatting ${selectedElement}</div>`;
    html += '<div class="dropdown-separator"></div>';

    if (!items.length) {
      html += '<div class="dropdown-item disabled">No date formats available</div>';
    } else {
      html += items.map(item =>
          `<div class="dropdown-item selectable-item date-format-item" data-value="${item.value}" data-element="${selectedElement}">
          ${item.label}
        </div>`
      ).join('');
    }

    return html;
  }

  handleSelection(element) {
    if (!this.currentTarget) {
      this.updateStatus('No field selected - please focus on a template field first');
      return;
    }

    const value = element.dataset.value;
    const isDateFormat = element.classList.contains('date-format-item');

    if (isDateFormat) {
      const selectedElement = element.dataset.element;
      this.handleDateFormatSelection(selectedElement, value);
    } else {
      this.insertAtCursor(value);
    }

    this.hideFlyout();
    this.hide(); // Close the entire dropdown

    // Update status to show what was inserted
    this.updateStatus(`Inserted: ${value.substring(0, 30)}${value.length > 30 ? '...' : ''}`);

    // Return focus to the target field
    setTimeout(() => {
      if (this.currentTarget) {
        this.currentTarget.focus();
      }
    }, 100);
  }

  handleDateFormatSelection(element, format) {
    if (typeof this.options.onDateFormatSelect === 'function') {
      const formattedValue = this.options.onDateFormatSelect(element, format);
      this.insertAtCursor(formattedValue);
    } else {
      this.insertAtCursor(`${element} ${format}`);
    }
  }

  insertAtCursor(value) {
    if (!this.currentTarget) return;

    const start = this.currentTarget.selectionStart || 0;
    const end = this.currentTarget.selectionEnd || 0;
    const text = this.currentTarget.value || '';

    this.currentTarget.value = text.substring(0, start) + value + text.substring(end);
    const newPosition = start + value.length;
    this.currentTarget.setSelectionRange(newPosition, newPosition);
  }

  // Data management methods
  updateMenuData(category, items) {
    this.menuData[category] = items;

    // If this category's flyout is currently open, refresh it
    if (this.activeFlyout === category) {
      const flyoutContent = this.generateFlyoutContent(category);
      this.flyoutMenu.innerHTML = flyoutContent;
    }

    // Optional: Trigger a visual indicator that data was updated
    this.updateStatus(`${category} data updated - ${items.length} items available`);
  }

  getSelectedDateElement() {
    if (!this.currentTarget) return null;

    const start = this.currentTarget.selectionStart;
    const end = this.currentTarget.selectionEnd;

    // If nothing is selected, return null
    if (start === end) return null;

    const selectedText = this.currentTarget.value.substring(start, end);

    // Check if the selected text matches ${...} pattern
    const match = selectedText.match(/^\$\{(.+)\}$/);

    if (match) {
      // Return the content inside the ${} - this will be used in the status message
      //return match[1];
      return match[0];
    }

    return null;
  }

  // Integration with existing API calls
  refreshSpaceData() {
    if (typeof customCode !== 'undefined' && customCode.getSpaceDetails) {
      customCode.getSpaceDetails();
    }
  }

  refreshKappData() {
    if (typeof customCode !== 'undefined' && customCode.getKappDetails) {
      customCode.getKappDetails();
    }
  }

  refreshFormData() {
    if (typeof customCode !== 'undefined' && customCode.getFormDetails) {
      customCode.getFormDetails();
    }
  }

  refreshSnippetData() {
    if (typeof customCode !== 'undefined' && customCode.getSnippetDetails) {
      customCode.getSnippetDetails();
    }
  }

  refreshDateFormatData() {
    if (typeof customCode !== 'undefined' && customCode.getDateFormatDetails) {
      customCode.getDateFormatDetails();
    }
  }
}

customCode.getSpaceDetails = function(){
  K('integration[Space]').load({
    values: {},
    success: function(data) {
      console.log('Space API response:', data);

      const items = [
        { label: "${space('Space Name')}", value: "${space('Space Name')}", isStandard: true },
        { label: "${space('Space Slug')}", value: "${space('Space Slug')}", isStandard: true }
      ];

      // Check if Attributes Map exists and is not null
      if (data && data['Attributes Map']) {
        Object.keys(data['Attributes Map']).forEach((attr) => {
          items.push({
            label: `\${spaceAttributes('${attr}')}`,
            value: `\${spaceAttributes('${attr}')}`,
            isStandard: false
          });
        });
      }

      // Update the dropdown
      if (customCode.dropdown) {
        customCode.dropdown.updateMenuData('Space', items);
      }
    },
    error: function(error) {
      console.error('Error loading space details:', error);
    }
  })
}

