customCode.getFormDetails = function() {
  K('integration[Form by Slug]').load({
    values: {},
    success: function(data) {
      console.log('Form API response:', data);

      const items = [];
      const standards = ['Form Name', 'Form Slug', 'Form Description', 'Form Status', 'Form Notes', 'Form Type'];
      standards.forEach((item) =>{
        items.push({
          label: `\${form('${item}')}`,
          value: `\${form('${item}')}`,
          isStandard: true
        });
      });

      // Check if Attributes Map exists and is not null
      if (data && data['Attributes Map']) {
        Object.keys(data['Attributes Map']).forEach((attr) => {
          items.push({
            label: `\${formAttributes('${attr}')}`,
            value: `\${formAttributes('${attr}')}`,
            isStandard: false
          });
        });
      }

      // Update the dropdown
      if (customCode.dropdown) {
        customCode.dropdown.updateMenuData('Form', items);
      }

      const submissionItems = [];
      const submissionStandards = ['handle', 'id', 'closedAt', 'closedBy', 'coreState', 'createAt', 'createdBy', 'label', 'submittedAt', 'submittedBy', 'type', 'updatedAt', 'updatedBy'];
      submissionStandards.forEach((item) =>{
        submissionItems.push({
          label: `\${submission('${item}')}`,
          value: `\${submission('${item}')}`,
          isStandard: true
        });
      });

      // Check if Fields exists and is an array
      if (data && data['Fields'] && Array.isArray(data['Fields'])) {
        data['Fields'].forEach((field) => {
          submissionItems.push({
            label: `\${values('${field['Field Name']}')}`,
