  var teams = identity('teams') || [];
  var appRolePattern = /^Role::App::([^:]+)::Admin::(Superuser|Notification Admin)$/;
  var matchedKappSlugs = teams
    .map(function(team) {
      var m = team.match(appRolePattern);
      return m ? m[1] : null;
